def parse_command_string(command_string):
    """Parse a command string into command name and arguments, handling quoted strings."""
    tokens = []
    current_token = []
    in_quotes = None

    for char in command_string:
        if in_quotes:
            if char == in_quotes:
                in_quotes = None
            else:
                current_token.append(char)
        elif char in ('"', "'"):
            in_quotes = char
        elif char == ' ':
            if current_token:
                tokens.append(''.join(current_token))
                current_token = []
        else:
            current_token.append(char)

    if current_token:
        tokens.append(''.join(current_token))

    return tokens


def validate_command(tokens):
    """Validate the parsed command tokens. Returns (is_valid, error_message)."""
    if not tokens:
        return False, "Empty command"

    command_name = tokens[0].upper()

    # Check against blocked commands
    if command_name in BLOCKED_COMMANDS:
        return False, f"Command '{command_name}' is blocked for security reasons"

    # Check against allowlist
    if command_name not in ALLOWED_COMMANDS:
        return False, f"Command '{command_name}' is not in the allowed commands list"

    # Check argument count
    if len(tokens) - 1 > MAX_ARGS:
        return False, f"Too many arguments (max {MAX_ARGS})"

    # Check argument lengths
    for i, token in enumerate(tokens):
        if len(token) > MAX_ARG_LENGTH:
            return False, f"Argument {i} exceeds maximum length of {MAX_ARG_LENGTH}"

    # Special validation for KEYS command - block broad patterns
    if command_name == 'KEYS':
        if len(tokens) < 2:
            return False, "KEYS command requires a pattern argument"
        pattern = tokens[1]
        # Block overly broad patterns that could cause performance issues
        if pattern == '*':
            return False, "KEYS with bare wildcard '*' is blocked. Use SCAN instead or provide a more specific pattern"

    return True, None


def sanitize_argument(arg):
    """Sanitize an individual argument to prevent injection."""
    # Remove null bytes
    arg = arg.replace('\x00', '')
    # Remove newlines/carriage returns that could be used for protocol injection
    arg = arg.replace('\r', '').replace('\n', '')
    return arg


@app.route('/api/admin/redis', methods=['POST'])
def execute_redis_command():
    """Execute a validated Redis command from user input."""

    # Check for API key authentication
    api_key = request.headers.get('X-API-Key')
    if not api_key or api_key != app.config.get('ADMIN_API_KEY', 'change-me-in-production'):
        return jsonify({
            'success': False,
            'error': 'Unauthorized: Invalid or missing API key'
        }), 401

    # Get command from request
    command_string = request.args.get('command', '').strip()

    if not command_string:
        # Also check JSON body
        data = request.get_json(silent=True)
        if data and 'command' in data:
            command_string = data['command'].strip()

    if not command_string:
        return jsonify({
            'success': False,
            'error': 'Missing required parameter: command'
        }), 400

    # Limit overall command length
    if len(command_string) > 4096:
        return jsonify({
            'success': False,
            'error': 'Command string exceeds maximum length of 4096 characters'
        }), 400

    # Parse the command string
    tokens = parse_command_string(command_string)

    if not tokens:
        return jsonify({
            'success': False,
            'error': 'Could not parse command'
        }), 400

    # Validate the command
    is_valid, error_message = validate_command(tokens)
    if not is_valid:
        return jsonify({
            'success': False,
            'error': error_message
        }), 403

    # Sanitize all arguments
    sanitized_tokens = [sanitize_argument(t) for t in tokens]
    command_name = sanitized_tokens[0].upper()
    args = sanitized_tokens[1:]

    # Log the command for audit trail
    app.logger.info(
        f"Redis command executed - User: {request.remote_addr}, "
        f"Command: {command_name}, Args: {args}"
    )

    try:
        result = redis_client.execute_command(command_name, *args)

        # Convert bytes to strings if needed
        if isinstance(result, bytes):
            result = result.decode('utf-8', errors='replace')
        elif isinstance(result, list):
            result = [
                item.decode('utf-8', errors='replace') if isinstance(item, bytes) else item
                for item in result
            ]
        elif isinstance(result, dict):
            result = {
                (k.decode('utf-8', errors='replace') if isinstance(k, bytes) else k):
                (v.decode('utf-8', errors='replace') if isinstance(v, bytes) else v)
                for k, v in result.items()
            }

        return jsonify({
            'success': True,
            'command': command_name,
            'args': args,
            'result': result
        })

    except redis.RedisError as e:
        app.logger.error(f"Redis error: {str(e)}")
        return jsonify({
            'success': False,
            'error': f"Redis error: {str(e)}"
        }), 500
    except Exception as e:
        app.logger.error(f"Unexpected error: {str(e)}")
        return jsonify({
            'success': False,
            'error': 'An unexpected error occurred'
        }), 500


